    while ~isnumeric(str2double(choice)) || str2double(choice) < 1 || str2double(choice) > 5
        disp('Invalid choice. Please enter a number between 1 and 5.');
        choice = input('Enter your choice (1-5): ', 's');
    end

    % Perform operation based on user choice
    switch str2double(choice)
        case 1
            disp('Addition');
            num1 = input('Enter first number: ');
            num2 = input('Enter second number: ');
            result = num1 + num2;
            disp(['Result: ', num2str(result)]);
        case 2
            disp('Subtraction');
            num1 = input('Enter first number: ');
            num2 = input('Enter second number: ');
            result = num1 - num2;
            disp(['Result: ', num2str(result)]);
        case 3
            disp('Multiplication');
            num1 = input('Enter first number: ');
            num2 = input('Enter second number: ');
            result = num1 * num2;
            disp(['Result: ', num2str(result)]);
        case 4
            disp('Division');
            num1 = input('Enter first number: ');
            num2 = input('Enter second number: ');
            result = num1 / num2;
            disp(['Result: ', num2str(result)]);
        case 5
            disp('Exiting the calculator.');
            return;
        otherwise
            disp('Invalid choice. Please try again.');
    end
end
